# ── Helper functions ────────────────────────────────────────────────────────


def get_supplement_rate(hs_code: str) -> dict | None:
    """
    Get combined customs duty + purchase tax for a 10-digit HS code.

    Returns dict with keys:
      customs_rate, customs_en, purchase_tax, purchase_tax_en, mu_id
    or None if not found.

    Tries exact 10-digit match first, then strips trailing zeros.
    """
    code = (hs_code or '').replace('.', '').replace('/', '').replace(' ', '').strip()
    # Pad to 10 digits
    if len(code) < 10:
        code = code.ljust(10, '0')
    # Exact match
    if code in SUPPLEMENT_RATES:
        return SUPPLEMENT_RATES[code]
    # Try parent codes (strip trailing zeros)
    for trim in (8, 6, 4):
        parent = code[:trim].ljust(10, '0')
        if parent in SUPPLEMENT_RATES:
            return SUPPLEMENT_RATES[parent]
    return None


def get_general_customs(hs_code: str) -> dict | None:
    """Get general customs duty rate for a 10-digit HS code."""
    code = (hs_code or '').replace('.', '').replace('/', '').replace(' ', '').strip()
    if len(code) < 10:
        code = code.ljust(10, '0')
    if code in GENERAL_CUSTOMS:
        return GENERAL_CUSTOMS[code]
    for trim in (8, 6, 4):
        parent = code[:trim].ljust(10, '0')
        if parent in GENERAL_CUSTOMS:
            return GENERAL_CUSTOMS[parent]
    return None


def get_purchase_tax(hs_code: str) -> dict | None:
    """Get purchase tax rate for a 10-digit HS code."""
    code = (hs_code or '').replace('.', '').replace('/', '').replace(' ', '').strip()
    if len(code) < 10:
        code = code.ljust(10, '0')
    if code in PURCHASE_TAX:
        return PURCHASE_TAX[code]
    for trim in (8, 6, 4):
        parent = code[:trim].ljust(10, '0')
        if parent in PURCHASE_TAX:
            return PURCHASE_TAX[parent]
    return None


def get_statistical_unit(mu_id: int) -> dict | None:
    """
    Get statistical unit info for a MeasurementUnitID.

    Returns {en: str, he: str} or None.
    """
    return STATISTICAL_UNITS.get(mu_id)


def get_unit_for_hs(hs_code: str) -> dict | None:
    """
    Get the statistical/measurement unit for an HS code.

    Returns {en: str, he: str} or None if percentage-based or not found.
    """
    data = get_supplement_rate(hs_code)
    if data and data.get('mu_id'):
        return STATISTICAL_UNITS.get(data['mu_id'])
    return None

